}


help_help_codes &lt;- function(input) {
    state_fips &lt;- c(
    AL = "01", AK = "02", AZ = "04", AR = "05", CA = "06",
    CO = "08", CT = "09", DE = "10", DC = "11", FL = "12",
    GA = "13", HI = "15", ID = "16", IL = "17", IN = "18",
    IA = "19", KS = "20", KY = "21", LA = "22", ME = "23",
    MD = "24", MA = "25", MI = "26", MN = "27", MS = "28",
    MO = "29", MT = "30", NE = "31", NV = "32", NH = "33",
    NJ = "34", NM = "35", NY = "36", NC = "37", ND = "38",
    OH = "39", OK = "40", OR = "41", PA = "42", RI = "44",
    SC = "45", SD = "46", TN = "47", TX = "48", UT = "49",
    VT = "50", VA = "51", WA = "53", WV = "54", WI = "55",
    WY = "56"
  )
  region_codes &lt;- c(
    Northeast = "1",
    Midwest   = "2",
    South     = "3",
    West      = "4"
  )
  division_codes &lt;- c(
    New_England        = "1",
    Middle_Atlantic    = "2",
    East_North_Central = "3",
    West_North_Central = "4",
    South_Atlantic     = "5",
    East_South_Central = "6",
    West_South_Central = "7",
    Mountain           = "8",
    Pacific            = "9"
  )
  if ((input %in% names(state_fips))) {
    code &lt;- state_fips[[input]]
  } else if (input %in% names(region_codes)) {
    code &lt;- region_codes[[input]]
  } else if (input %in% names(division_codes)) {
    code &lt;- division_codes[[input]]
  }
    else if (input %in% c(state_fips, region_codes, division_codes)) {
    code &lt;- input
  }
  else {
    stop("Invalid input.")
  }
  code
}

